-- VERIFICATION QUERIES
-- ═══════════════════════════════════════════════════════════════════════════════

-- Total entries in table after both V9 files
SELECT 'TOTAL ENTRIES' AS metric, COUNT(*) AS value FROM industry_solutions;

-- Breakdown by type
SELECT product_type, COUNT(*) FROM industry_solutions GROUP BY product_type ORDER BY product_type;

-- New product categories added
SELECT category, product_type, COUNT(DISTINCT product_slug) AS unique_products, COUNT(*) AS total_entries
FROM industry_solutions
WHERE product_slug IN ('mailchimp','convertkit','activecampaign','getresponse','wix','squarespace','hostinger','hootsuite','sprout-social','birdeye','podium','nicejob','ringcentral','openphone','grasshopper','calendly','acuity','shipstation','easyship','legalzoom','rocket-lawyer','expensify','ramp','mercury-bank','relay-bank','jasper-ai','surfer-seo','backblaze','nordlayer','trainual','talentlms','pipedrive','monday-crm','docusign','pandadoc','bamboohr','deel','wistia','loom','tidio','intercom','typeform','jotform','bench','pilot','teachworks','tutorcruncher','towsql','vonigo','stageright','collect-stream','manageamerica','servicefusion','pricesync','booker','gymmasteraff','fishbowl-inv','sling-schedule','simpletexting','textmagic','mailchimp-free','brevo-free','mailerlite-free','wordpress-free','google-sites-free','carrd-free','buffer-free','canva-free','later-free','google-business-free','review-generation-diy','google-voice-free','cal-com-free','tidycal-free','pirate-ship-free','sba-free-resources','score-mentoring-free','sbdc-free','legal-templates-diy','gnucash-free','chatgpt-free','google-gemini-free','google-drive-free','duplicati-free','notion-free','google-workspace-essentials','loom-free','slack-free','discord-free','google-forms-free','tally-free','canada-bdc-free','canada-digital-adoption','sba-loans-free','uk-startup-loans','profit-first-diy','customer-avatar-diy','competitor-audit-diy','cash-flow-forecast-diy','google-analytics-free','google-search-console-free','sop-documentation-diy','kpi-dashboard-diy','exit-interview-diy','vendor-negotiation-diy','local-seo-diy','referral-program-diy','seasonal-planning-diy')
GROUP BY category, product_type ORDER BY total_entries DESC;

-- Solutions per industry (should be 30-45+ each now)
SELECT industry_slug, COUNT(*) AS total,
  SUM(CASE WHEN product_type='AFFILIATE' THEN 1 ELSE 0 END) AS affiliates,
  SUM(CASE WHEN product_type='FREE' THEN 1 ELSE 0 END) AS free_tools
FROM industry_solutions GROUP BY industry_slug ORDER BY total DESC;

-- Top 20 most-assigned products
SELECT product_name, product_type, COUNT(*) AS industry_count
FROM industry_solutions GROUP BY product_name, product_type ORDER BY industry_count DESC LIMIT 20;